const express = require('express');
const app = express();

// Middleware for API key authentication
app.use((req, res, next) => {
  const apiKey = req.query.api_key;

  if (!apiKey) {
    return res.status(401).json({ message: 'Missing API key' });
  }

  req.headers['X-API-KEY'] = apiKey;
  next();
});

// Route for forwarding requests to backend services
app.use('/api', (req, res) => {
  const url = req.originalUrl.replace('/api', '');
  console.log(`Forwarding request to ${url} with API key: ${req.headers['X-API-KEY']}`);

  // Perform request forwarding logic here using libraries like Axios or request-promise
});

app.listen(3000, () => {
  console.log('API gateway listening on port 3000');
});